# Skeptic review S49-T1-A-E2: verify PASS/CONTINUE only on taught contract
def assess(record: dict) -> str:
    required = {'baseline_success', 'branch_count', 'tool_choice_uncertain', 'known_steps', 'case_id', 'agent_success'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not record["known_steps"] or record["agent_success"] <= record["baseline_success"] else "KEEP_DETERMINISTIC_WORKFLOW"

valid = {'case_id': 'CASO-AYA-049-1A', 'known_steps': True, 'branch_count': 2, 'tool_choice_uncertain': False, 'baseline_success': 0.96, 'agent_success': 0.9}
invalid = {'case_id': 'CASO-AYA-049-1A', 'known_steps': True, 'branch_count': 2, 'tool_choice_uncertain': False, 'baseline_success': -99.04, 'agent_success': 0.9}
incomplete = {**valid}
incomplete.pop('agent_success', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

